const transcript = $input.item.json.Transkript;

if (!transcript || transcript.trim().length < 20) {
  throw new Error("Transkript ist leer oder zu kurz.");
}

const detectLanguage = (text) => {
  const germanWords = ['der', 'die', 'das', 'und', 'in', 'zu', 'ist', 'von', 'mit', 'auf'];
  const englishWords = ['the', 'and', 'to', 'of', 'in', 'is', 'that', 'for', 'with', 'it'];

  const textLower = text.toLowerCase().split(/\s+/);
  const germanCount = textLower.filter(w => germanWords.includes(w)).length;
  const englishCount = textLower.filter(w => englishWords.includes(w)).length;

  return englishCount > germanCount ? 'english' : 'german';
};

const chunkTranscript = (text, maxTokens = 12000) => {
  const estimatedTokens = text.length / 4;

  if (estimatedTokens <= maxTokens) {
    return [{ chunk: text, index: 0, total: 1 }];
  }

  const chunkSize = maxTokens * 4;
  const overlapSize = chunkSize * 0.1;
  const chunks = [];
  let position = 0;
  const sentences = text.match(/[^.!?]+[.!?]+/g) || [text];
  let currentChunk = '';

  for (const sentence of sentences) {
    if ((currentChunk + sentence).length > chunkSize) {
      if (currentChunk) chunks.push(currentChunk.trim());
      currentChunk = sentence;
    } else {
      currentChunk += sentence;
    }
  }
  if (currentChunk) chunks.push(currentChunk.trim());

  return chunks.map((chunk, index) => ({
    chunk,
    index,
    total: chunks.length
  }));
};

const language = detectLanguage(transcript);
const chunks = chunkTranscript(transcript);

return {
  json: {
    meeting_title: $input.item.json["Meeting-Titel"] || "Unbenanntes Meeting",
    date: $input.item.json["Datum"] || new Date().toISOString().split('T')[0],
    transcript: chunks[0].chunk,
    original_length: transcript.length,
    language: language,
    chunks_total: chunks.length,
    all_chunks: chunks,
    is_chunked: chunks.length > 1
  }
};

