const error = $input.item.json.error || $input.item.json.message || 'Unbekannter Fehler';
const statusCode = $input.item.json.statusCode || 500;

return {
  json: {
    timestamp: new Date().toISOString(),
    error_source: "HTTP Request - Extraction",
    status_code: statusCode,
    error_message: error.toString(),
    recovery_status: "failed",
    workflow_terminated: true
  }
};

let parsed;
try {
  const rawContent = $input.item.json.content[0].text;
  const cleaned = rawContent.replace(/```json|```/g, "").trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error("Claude-Antwort konnte nicht als JSON geparst werden: " + e.message);
}

if (!Array.isArray(parsed.decisions) || !Array.isArray(parsed.tasks)) {
  throw new Error("Unerwartete JSON-Struktur von Claude erhalten.");
}

const validTasks = parsed.tasks.map(t => ({
  task: t.task || "Unbenannte Aufgabe",
  owner: t.owner || "Nicht zugewiesen",
  deadline: /^\d{4}-\d{2}-\d{2}$/.test(t.deadline) ? t.deadline : null,
  priority: ["hoch", "mittel", "niedrig"].includes(t.priority) ? t.priority : "mittel"
}));

return {
  json: {
    decisions: parsed.decisions,
    tasks: validTasks,
    task_count: validTasks.length,
    meeting_title: $('Preprocessing & Language Detection').item.json.meeting_title,
    date: $('Preprocessing & Language Detection').item.json.date,
    summary: $('HTTP Request - Summary').item.json.content[0].text,
    language: $('Preprocessing & Language Detection').item.json.language
  }
};

const logEntry = {
  timestamp: new Date().toISOString(),
  event: "workflow_completed",
  meeting_title: $('Parse & Validate Results').item.json.meeting_title,
  date: $('Parse & Validate Results').item.json.date,
  decisions_count: $('Parse & Validate Results').item.json.decisions.length,
  tasks_created: $('Parse & Validate Results').item.json.task_count,
  language: $('Parse & Validate Results').item.json.language,
  status: "success"
};

return {
  json: logEntry
};
